// The Webhook node delivers the raw Telegram update under .body. Normalize
// message | edited_message | callback_query into one shape, and DROP anything
// not from the single authorized operator chat (replaces the Telegram Trigger's
// restrictToChatIds; Caddy already validated the secret token at the edge).
// @@CHAT_ID@@ is substituted at install time.
const u = ($input.first().json && $input.first().json.body) || $input.first().json || {};
const cb = u.callback_query || null;
const msg = u.message || u.edited_message || (cb && cb.message) || {};
const isCallback = !!cb;
let text = isCallback ? (cb.data || '') : (msg.text || msg.caption || '');
text = String(text).trim();
const chatId = (msg.chat && msg.chat.id) || (cb && cb.from && cb.from.id) || '';
if (String(chatId) !== '@@CHAT_ID@@') { return []; }
if (!text) { return []; }
const updateId = Number(u.update_id || 0);
return [{ json: { text: text, chat_id: chatId, kind: isCallback ? 'callback_query' : (u.edited_message ? 'edited_message' : 'message'), update_id: updateId } }];
